const f = $input.first().json;
const baseUrl = $env.APP_BASE_URL || 'https://workflow-consultancy.vercel.app';
const reportUrl = f.reportId ? baseUrl + '/report?id=' + f.reportId : '';
const portalUrl = baseUrl + '/portal';

var ctaText = 'View Your Report';
var ctaUrl = reportUrl;
var ctaColor = '#6366f1';

if (f.followupType === 'day14') {
  ctaText = 'Book a Quick Wins Call';
  ctaUrl = 'mailto:hope@vesno.ai?subject=Quick Wins Call - ' + encodeURIComponent(f.company || '');
  ctaColor = '#16a34a';
} else if (f.followupType === 'day30') {
  ctaText = 'Schedule Your Strategy Session';
  ctaUrl = 'mailto:hope@vesno.ai?subject=Strategy Session - ' + encodeURIComponent(f.company || '');
  ctaColor = '#1e40af';
}

var stageLabels = { day3: 'Quick Check-In', day14: 'Two Week Review', day30: 'Monthly Strategy Update' };
var stageLabel = stageLabels[f.followupType] || 'Follow-Up';

var html = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<p style="margin: 0 0 4px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.7;">' + stageLabel + '</p>' +
    '<h1 style="margin: 0; font-size: 22px;">' + f.subject + '</h1>' +
    (f.company ? '<p style="margin: 8px 0 0; opacity: 0.8; font-size: 14px;">For ' + f.company + '</p>' : '') +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155; line-height: 1.6;">' + f.message + '</p>' +
    (reportUrl && f.followupType === 'day3' ? '<div style="margin: 20px 0; padding: 16px; background: #f0f9ff; border-radius: 8px; border-left: 4px solid #3b82f6;"><p style="margin: 0; font-size: 14px; color: #1e40af;"><strong>Your report is still available:</strong> view your full analysis including process maps, automation scores, and your personalised 90-day roadmap.</p></div>' : '') +
    (f.followupType === 'day14' ? '<div style="margin: 20px 0; padding: 16px; background: #f0fdf4; border-radius: 8px; border-left: 4px solid #22c55e;"><p style="margin: 0; font-size: 14px; color: #166534;"><strong>Did you know?</strong> Companies that act on quick wins within 30 days see results 3x faster than those who wait.</p></div>' : '') +
    (f.followupType === 'day30' ? '<div style="margin: 20px 0; padding: 16px; background: #eff6ff; border-radius: 8px; border-left: 4px solid #1e40af;"><p style="margin: 0; font-size: 14px; color: #1e3a8a;"><strong>Your roadmap is ready.</strong> The 90-day transformation plan from your process audit is designed to deliver measurable results within the first quarter.</p></div>' : '') +
    '<div style="margin: 28px 0 20px; text-align: center;">' +
      '<a href="' + ctaUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, ' + ctaColor + ', ' + ctaColor + 'dd); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">' + ctaText + '</a>' +
    '</div>' +
    '<p style="text-align: center; margin: 16px 0 0;"><a href="' + portalUrl + '" style="font-size: 13px; color: #6366f1; text-decoration: underline;">Manage your reports in the Client Portal</a></p>' +
    '<hr style="border: none; border-top: 1px solid #e2e8f0; margin: 24px 0;">' +
    '<p style="font-size: 12px; color: #94a3b8; text-align: center;">You\'re receiving this because you completed a process audit with us. No further automated emails will be sent after this series.</p>' +
  '</div>' +
'</div>';

return {
  json: {
    to: f.email,
    subject: f.subject,
    html: html,
    reportId: f.reportId,
    followupType: f.followupType
  }
};
